def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        base_score = 0.0
        penalty_sum = 0.0
        decay_factor = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio > 2:
            for power in range(1, 5):
                penalty_sum += (ratio ** (2 * power)) / (power ** 2 + 1)
            base_score = (ratio ** 4) / 3 + penalty_sum
            priorities[i] = base_score * 2
        elif 1 < ratio <= 2:
            for q in range(1, 7):
                sign = (-1) ** q
                base_score += sign * (ratio ** q) / (q + 1)
            for r in range(1, 4):
                decay_factor *= (1 - 1/(r + ratio + 1))
            priorities[i] = abs(base_score) * decay_factor * 10
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 10):
                if p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                else:
                    temp_score -= (ratio ** p) / (p * 3)
            multiplier = 20 if ratio < 0.25 else 15 if ratio < 0.5 else 10 if ratio < 0.75 else 5
            base_score = abs(temp_score) * multiplier
            if ratio > 0.9:
                extra = 0
                for m in range(1, 5):
                    extra += (ratio ** m) / (m + 2)
                base_score += extra * 1.5
            priorities[i] = base_score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
